mapper.insert:
 		insert into cotdl.tbl_piistep 
		select jobid, TO_NUMBER(version)+1, stepid, stepname, steptype, stepseq, db, status, 'CHECKOUT', threadcnt, commitcnt, enddate, regdate, SYSDATE as upddate, reguserid, upduserid
          from cotdl.tbl_piistep where jobid= #{jobid} and version= #{version, jdbcType=VARCHAR}

mapper.update:
update cotdl.tbl_piistep
set 
	stepseq= #{stepseq}
where jobid= #{jobid, jdbcType=VARCHAR} and version= #{version, jdbcType=VARCHAR} and stepid= #{stepid, jdbcType=VARCHAR}

update cotdl.tbl_piistep
set
	status= #{status, jdbcType=VARCHAR}
where jobid= #{jobid, jdbcType=VARCHAR} and version= #{version, jdbcType=VARCHAR}
  and steptype= #{steptype}

mapper.select:
 
		 
		select 
			jobid, version, stepid, stepname, steptype, stepseq, db, status, phase, threadcnt, commitcnt, enddate, regdate, upddate, reguserid, upduserid
		from ( 
				select  
					 ROWNUM rn, jobid, version, stepid, stepname, steptype, stepseq, db, status, phase, threadcnt, commitcnt, enddate, regdate, upddate, reguserid, upduserid
				from (
						select jobid, version, stepid, stepname, steptype, stepseq, db, status, phase, threadcnt, commitcnt, to_char(enddate,'yyyy/mm/dd') as enddate, to_char(regdate,'yyyy/mm/dd') as regdate, to_char(upddate,'yyyy/mm/dd') as upddate, reguserid, upduserid
						  from cotdl.tbl_piistep order by jobid, stepseq
					 ) a
				where  
		
	    
		
						
							and upper(jobid) = upper(#{search1, jdbcType=VARCHAR})
						
						
							and version = #{search2}
						
						
							and stepid = #{search3}
						
		
	    
	    
				 ROWNUM <= #{pagenum} * #{amount} 
				order by jobid, stepseq
			  ) c
		where rn > (#{pagenum} -1) * #{amount} 
		order by jobid, stepseq
